/// 全局堆分配器
static HEAP_ALLOCATOR: LockedHeap<32> = LockedHeap::empty();

// 标记为全局分配错误处理器
#[alloc_error_handler]
/// 分配错误处理
pub fn handle_alloc_error(layout: core::alloc::Layout) -> ! {
    println!("Heap allocation error:");
    println!("  Requested size: {} bytes", layout.size());
    println!("  Requested alignment: {} bytes", layout.align());
    println!("  Total heap size: {} bytes", KERNEL_HEAP_SIZE);
    println!("  Requested size in MB: {:.2} MB", layout.size() as f64 / (1024.0 * 1024.0));
    println!("  Total heap size in MB: {:.2} MB", KERNEL_HEAP_SIZE as f64 / (1024.0 * 1024.0));

    panic!("Heap allocation error, layout = {:?}", layout);
}

/// 全局堆内存空间
static mut HEAP_SPACE: [u8; KERNEL_HEAP_SIZE] = [0; KERNEL_HEAP_SIZE];

/// 初始化用于内核加载开始时的堆
pub fn init_heap() {
    unsafe {
        HEAP_ALLOCATOR
            .lock()
            // 起始地址和大小
            .init(HEAP_SPACE.as_ptr() as usize, KERNEL_HEAP_SIZE);
        println!("heap_space start: {:#x?}", HEAP_SPACE.as_ptr());
    }
}

