impl VirtAddr {
    /// 计算地址所在的页号（向下取整）
    pub fn floor(&self) -> VirtPageNum {
        let a = self.0 / PAGE_SIZE;
        VirtPageNum(a)
    }
    /// 计算地址所在的页号（向上取整）
    pub fn ceil(&self) -> VirtPageNum {
        let b = (self.0 - 1 + PAGE_SIZE) / PAGE_SIZE;
        VirtPageNum(b)
    }
    /// 计算地址在页内的偏移量
    pub fn page_offset(&self) -> usize {
        {
            let c = PAGE_SIZE - 1;
            self.0 & (c)
        }
    }
    /// 检查地址是否页对齐
    pub fn aligned(&self) -> bool {
        self.page_offset() == 0
    }
}

