    }
    /// 以字节数组形式获取可变引用
    pub fn get_bytes_mut<T>(&self) -> &'static [u8] {
        unsafe { core::slice::from_raw_parts_mut(self.0 as *mut u8, core::mem::size_of::<T>()) }
    }
}

impl PhysPageNum {
    /// 获取页的起始地址
