impl Frame {
    pub fn insert_in_memory(
        &mut self,
        frame_tracker: Arc<FrameTracker>,
    ) -> Result<(), MemoryError> {
        match self {
            Frame::Unallocated => {
                *self = Frame::InMemory(frame_tracker);
