    }
    pub fn take_in_memory(&mut self) -> Option<Arc<FrameTracker>> {
        match self {
            Frame::InMemory(frame_ref) => {
                // avoid implement trait 'Copy'
                let frame = unsafe { core::ptr::read(frame_ref) };
