    #[cfg(feature = "oom_handler")]
    pub fn force_swap_out(&mut self) -> Result<usize, MemoryError> {
        match self {
            Frame::InMemory(frame_ref) => {
                let swap_tracker = SWAP_DEVICE.lock().write(frame_ref.ppn.get_bytes_array());
