/// 共享内存段的唯一标识符
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct SharedSegmentId {
    /// 对于文件映射：文件inode号 + 偏移量的hash
    /// 对于匿名映射：唯一生成的ID
    pub id: u64,
}

impl SharedSegmentId {
    /// 为文件映射创建共享段ID
    pub fn from_file(file: &Arc<dyn File>, offset: usize) -> Self {
        // 使用文件的地址和偏移量来生成唯一ID
        let mut hasher = 0u64;
        // 简单的hash算法，使用文件对象的地址作为标识
        let file_ptr = Arc::as_ptr(file);
        let file_addr = file_ptr as *const () as usize;
        hasher = hasher.wrapping_mul(31).wrapping_add(file_addr as u64);
        hasher = hasher.wrapping_mul(31).wrapping_add(offset as u64);
        Self { id: hasher }
    }

    /// 为匿名映射创建共享段ID
    pub fn new_anonymous() -> Self {
        static NEXT_ANON_ID: Mutex<u64> = Mutex::new(0x8000_0000_0000_0000u64);
        let mut next_id = NEXT_ANON_ID.lock();
        let id = *next_id;
        *next_id += 1;
        Self { id }
    }
}

/// 共享内存段
pub struct SharedSegment {
    /// 段ID
    pub id: SharedSegmentId,
    /// 物理页面，按页偏移索引
    pub pages: BTreeMap<usize, Arc<FrameTracker>>,
    /// 如果是文件映射，保存文件引用
    pub file: Option<Arc<dyn File>>,
    /// 文件中的起始偏移量
    pub file_offset: usize,
    /// 段的总大小（页数）
    pub page_count: usize,
    /// 引用计数（有多少个进程在使用）
    pub ref_count: usize,
    /// 文件是否已被删除（unlinked）但仍有引用
    pub file_unlinked: bool,
}

impl SharedSegment {
    /// 创建新的共享段
    pub fn new(
        id: SharedSegmentId,
        page_count: usize,
        file: Option<Arc<dyn File>>,
        file_offset: usize,
    ) -> Self {
        Self {
            id,
            pages: BTreeMap::new(),
            file,
            file_offset,
            page_count,
            ref_count: 0,
            file_unlinked: false,
        }
    }

    /// 获取指定页面，如果不存在则分配
    pub fn get_or_alloc_page(&mut self, page_offset: usize) -> Option<Arc<FrameTracker>> {
        if page_offset >= self.page_count {
            return None;
        }

        if let Some(frame) = self.pages.get(&page_offset) {
            Some(frame.clone())
        } else {
            // 分配新页面
            let frame = super::frame_alloc()?;

            // 如果是文件映射，尝试从文件读取数据
            if let Some(file) = &self.file {
                let file_pos = self.file_offset + page_offset * crate::config::PAGE_SIZE;

                // 先分配并清零页面
                let page_data = unsafe {
                    core::slice::from_raw_parts_mut(
                        super::PhysAddr::from(frame.ppn).0 as *mut u8,
                        crate::config::PAGE_SIZE,
                    )
                };
                page_data.fill(0);

                // 只有在文件没有被unlink的情况下才尝试读取
                if !self.file_unlinked {
                    // 尝试从文件读取数据，如果文件已被删除则忽略错误
                    let old_offset = file.get_offset();
                    if file.lseek(file_pos as isize, crate::fs::SeekWhence::SEEK_SET).is_ok() {
                        // 尝试读取文件内容到页面，忽略可能的错误
                        let _bytes_read = file.read(None, page_data);
                        // 无论读取成功与否，都恢复文件偏移量
                        let _ = file.lseek(old_offset as isize, crate::fs::SeekWhence::SEEK_SET);
                    }
                }
                // 如果文件被unlink或操作失败，页面已经被清零，这是安全的
            } else {
                // 匿名映射，清零页面
                let page_data = unsafe {
                    core::slice::from_raw_parts_mut(
                        super::PhysAddr::from(frame.ppn).0 as *mut u8,
                        crate::config::PAGE_SIZE,
                    )
                };
                page_data.fill(0);
            }

            self.pages.insert(page_offset, frame.clone());
            Some(frame)
        }
    }

    /// 增加引用计数
    pub fn add_ref(&mut self) {
        self.ref_count += 1;
        trace!("[SharedSegment] ref_count increased to {} for segment {:?}", self.ref_count, self.id);
    }

    /// 减少引用计数，返回是否应该删除此段
    pub fn remove_ref(&mut self) -> bool {
        if self.ref_count > 0 {
            self.ref_count -= 1;
        }
        trace!("[SharedSegment] ref_count decreased to {} for segment {:?}", self.ref_count, self.id);
        self.ref_count == 0
    }

    /// 写回文件映射的页面（如果需要）
    pub fn sync_to_file(&self) {
        if let Some(file) = &self.file {
            // 如果文件已被unlink，则不进行同步
            if self.file_unlinked {
                trace!("[SharedSegment] File was unlinked, skipping sync");
                return;
            }

            // 尝试获取当前偏移量，如果文件无效则直接返回
            let old_offset = match file.lseek(0, crate::fs::SeekWhence::SEEK_CUR) {
                Ok(offset) => offset,
                Err(_) => {
                    // 文件可能已被删除，无法同步
                    trace!("[SharedSegment] File is invalid, cannot sync to file");
                    return;
                }
            };

            for (&page_offset, frame) in &self.pages {
                let file_pos = self.file_offset + page_offset * crate::config::PAGE_SIZE;

                // 尝试定位到文件位置
                if file.lseek(file_pos as isize, crate::fs::SeekWhence::SEEK_SET).is_ok() {
                    let page_data = unsafe {
                        core::slice::from_raw_parts(
                            super::PhysAddr::from(frame.ppn).0 as *const u8,
                            crate::config::PAGE_SIZE,
                        )
                    };

                    // 尝试写入，忽略错误（文件可能已被删除）
                    let _ = file.write(None, page_data);
                } else {
                    // 如果无法定位，说明文件可能已被删除，跳过此页面
                    break;
                }
            }

            // 尝试恢复文件偏移量
            let _ = file.lseek(old_offset as isize, crate::fs::SeekWhence::SEEK_SET);
        }
    }

    /// 标记文件已被unlink
    pub fn mark_file_unlinked(&mut self) {
        self.file_unlinked = true;
        trace!("[SharedSegment] Marked file as unlinked for segment {:?}", self.id);
    }
}

