#[no_mangle]
pub fn trap_handler() -> ! {
    set_kernel_trap_entry();
    {
        let task = current_task().unwrap();
        let mut inner = task.acquire_inner_lock();
        inner.update_process_times_enter_trap();
    }
    let scause = scause::read();
    let stval = stval::read();
    match scause.cause() {
        Trap::Exception(Exception::UserEnvCall) => {
            // jump to next instruction anyway
            let mut cx = current_trap_cx();
            cx.gp.pc += 4;
            // get system call return value
            let result = syscall(
                cx.gp.a7,
                [cx.gp.a0, cx.gp.a1, cx.gp.a2, cx.gp.a3, cx.gp.a4, cx.gp.a5],
            );
            // cx is changed during sys_exec, so we have to call it again
            cx = current_trap_cx();
            cx.gp.a0 = result as usize;
        }
        Trap::Exception(Exception::StoreFault)
        | Trap::Exception(Exception::StorePageFault)
        | Trap::Exception(Exception::InstructionFault)
        | Trap::Exception(Exception::InstructionPageFault)
        | Trap::Exception(Exception::LoadFault)
        | Trap::Exception(Exception::LoadPageFault) => {
            let task = current_task().unwrap();
            let mut inner = task.acquire_inner_lock();
            let addr = VirtAddr::from(stval);
            log::debug!(
                "[page_fault] pid: {}, type: {:?}",
                task.pid.0,
                scause.cause()
            );
            // This is where we handle the page fault.
            frame_reserve(3);
            if let Err(error) = task.vm.lock().do_page_fault(addr) {
                match error {
                    MemoryError::BeyondEOF => {
                        inner.add_signal(Signals::SIGBUS);
                    }
                    MemoryError::NoPermission | MemoryError::BadAddress => {
                        inner.add_signal(Signals::SIGSEGV);
                    }
                    _ => unreachable!(),
                }
            };
        }
        Trap::Exception(Exception::IllegalInstruction) => {
            let task = current_task().unwrap();
            let mut inner = task.acquire_inner_lock();
            inner.add_signal(Signals::SIGILL);
        }
        Trap::Interrupt(Interrupt::SupervisorTimer) => {
            do_wake_expired();
            crate::fs::procfs::interrupts::Interrupts::increment_interrupt_count(5);
            set_next_trigger();
            suspend_current_and_run_next();
        }
        Trap::Interrupt(Interrupt::SupervisorExternal) => {
            // 记录外部中断次数（中断号9）
            crate::fs::procfs::interrupts::Interrupts::increment_interrupt_count(9);
            // 这里可以添加具体的外部中断处理逻辑
            suspend_current_and_run_next();
        }
        _ => {
            panic!(
                "Unsupported trap {:?}, stval = {:#x}!",
                scause.cause(),
                stval
            );
        }
    }
    {
        let task = current_task().unwrap();
        let mut inner = task.acquire_inner_lock();
        inner.update_process_times_leave_trap(scause.cause());
    }
    trap_return();
}

#[no_mangle]
pub fn trap_return() -> ! {
    do_signal();
    set_user_trap_entry();
    let task = current_task().unwrap();
    let trap_cx_ptr = task.trap_cx_user_va();
    let user_satp = task.get_user_token();
    drop(task);
    let restore_va = __restore as usize - __alltraps as usize + TRAMPOLINE;
    unsafe {
        asm!(
            "fence.i",
            "jr {restore_va}",
            restore_va = in(reg) restore_va,
            in("a0") trap_cx_ptr,
            in("a1") user_satp,
            options(noreturn)
        );
    }
}

#[no_mangle]
pub fn trap_from_kernel() -> ! {
    panic!(
        "a trap {:?} from kernel! bad addr = {:#x}, bad instruction = {:#x}",
        scause::read().cause(),
        stval::read(),
        match current_task() {
            Some(task) => {
                task.acquire_inner_lock().get_trap_cx().gp.pc
            }
            None => {
                sepc::read()
            }
        }
    );
}

